"""GET /api/market/<symbol> — real-time market data and company details."""

import logging
from datetime import datetime, timezone

from flask import Blueprint, jsonify

from app.auth.middleware import require_auth
from app.middleware.rate_limit import limiter
from app.services.market_data import PolygonClient

logger = logging.getLogger("signal.market")

market_bp = Blueprint("market", __name__)

# Singleton client — disabled gracefully when POLYGON_API_KEY is unset
_polygon = PolygonClient()


@market_bp.route("/api/market/<symbol>")
@require_auth
@limiter.limit("60 per minute")
def market_snapshot(symbol: str):
    """Return real-time price data for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    data = _polygon.get_ticker_snapshot(symbol)
    if data is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No market data available for symbol '{symbol.upper()}'",
        }), 404

    data["updated_at"] = datetime.now(timezone.utc).isoformat()
    return jsonify(data)


@market_bp.route("/api/market/<symbol>/details")
@require_auth
@limiter.limit("60 per minute")
def market_details(symbol: str):
    """Return company fundamentals for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    data = _polygon.get_ticker_details(symbol)
    if data is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No company details available for symbol '{symbol.upper()}'",
        }), 404

    return jsonify(data)

"""Tests for market data API endpoints (US-010)."""

from datetime import datetime, timezone
from unittest.mock import patch, MagicMock

import pytest

from app.models import User
from app.services.feed_parser import utc_iso


def _auth_headers():
    return {"Authorization": "Bearer fake-token"}


def _create_user(db_session, tier="pro"):
    now = utc_iso(datetime.now(timezone.utc))
    user = User(
        firebase_uid="market-test-uid",
        email="market@example.com",
        display_name="Market Tester",
        tier=tier,
        created_at=now,
        updated_at=now,
    )
    db_session.add(user)
    db_session.commit()
    return user


class TestMarketSnapshotAuth:
    """Authentication requirements for /api/market/<symbol>."""

    def test_unauthenticated_returns_401(self, client):
        resp = client.get("/api/market/AAPL")
        assert resp.status_code == 401

    @patch("app.auth.firebase.verify_id_token")
    @patch("app.routes.market._polygon")
    def test_authenticated_returns_200(self, mock_polygon, mock_verify, client, db_session):
        mock_verify.return_value = {
            "uid": "market-test-uid",
            "email": "market@example.com",
            "name": "Market Tester",
        }
        _create_user(db_session, tier="pro")
        mock_polygon.enabled = True
        mock_polygon.get_ticker_snapshot.return_value = {
            "symbol": "AAPL",
            "price": 150.25,
            "change": 1.75,
            "change_percent": 1.18,
            "volume": 50000000,
            "vwap": 149.80,
        }
        resp = client.get("/api/market/AAPL", headers=_auth_headers())
        assert resp.status_code == 200


class TestMarketDetailsAuth:
    """Authentication requirements for /api/market/<symbol>/details."""

    def test_unauthenticated_returns_401(self, client):
        resp = client.get("/api/market/AAPL/details")
        assert resp.status_code == 401


class TestMarketSnapshot:
    """Snapshot endpoint response format and error handling."""

    @patch("app.auth.firebase.verify_id_token")
    @patch("app.routes.market._polygon")
    def test_snapshot_response_fields(self, mock_polygon, mock_verify, client, db_session):
        mock_verify.return_value = {
            "uid": "market-test-uid",
            "email": "market@example.com",
            "name": "Market Tester",
        }
        _create_user(db_session)
        mock_polygon.enabled = True
        mock_polygon.get_ticker_snapshot.return_value = {
            "symbol": "AAPL",
            "price": 150.25,
            "change": 1.75,
            "change_percent": 1.18,
            "volume": 50000000,
            "vwap": 149.80,
        }
        resp = client.get("/api/market/AAPL", headers=_auth_headers())
        data = resp.get_json()
        for field in ("symbol", "price", "change", "change_percent", "volume", "vwap", "updated_at"):
            assert field in data, f"Missing field: {field}"
        assert data["symbol"] == "AAPL"
        assert data["price"] == 150.25

    @patch("app.auth.firebase.verify_id_token")
    @patch("app.routes.market._polygon")
    def test_snapshot_404_unknown_ticker(self, mock_polygon, mock_verify, client, db_session):
        mock_verify.return_value = {
            "uid": "market-test-uid",
            "email": "market@example.com",
            "name": "Market Tester",
        }
        _create_user(db_session)
        mock_polygon.enabled = True
        mock_polygon.get_ticker_snapshot.return_value = None
        resp = client.get("/api/market/ZZZZZ", headers=_auth_headers())
        assert resp.status_code == 404
        data = resp.get_json()
        assert "error" in data
        assert "ZZZZZ" in data["message"]

    @patch("app.auth.firebase.verify_id_token")
    @patch("app.routes.market._polygon")
    def test_snapshot_503_when_disabled(self, mock_polygon, mock_verify, client, db_session):
        mock_verify.return_value = {
            "uid": "market-test-uid",
            "email": "market@example.com",
            "name": "Market Tester",
        }
        _create_user(db_session)
        mock_polygon.enabled = False
        resp = client.get("/api/market/AAPL", headers=_auth_headers())
        assert resp.status_code == 503
        assert resp.headers.get("Retry-After") == "60"
        data = resp.get_json()
        assert "error" in data


